    cin>>a1>>a2>>a3>>a4>>a5;

    n=n+a1%3;
    a1=a1/3;
    a2=a2+a1;
    a5=a5+a1;

    n=n+a2%3;
    a2=a2/3;
    a3=a3+a2;
    a1=a1+a2;
    
    n=n+a3%3;
    a3=a3/3;
    a4=a4+a3;
    a2=a2+a3;
    

    n=n+a4%3;
    a4=a4/3;
    a5=a5+a4;
    a3=a3+a4;
    
    n=n+a5%3;
    a5=a5/3;
    a1=a1+a5;
    a4=a4+a5;

    cout<<a1<<" "<<a2<<" "<<a3<<" "<<a4<<" "<<a5<<endl;
    cout<<n<<endl;
    return 0;
}
